/*
 * data.js — ゲームの全データ（データ駆動の心臓部）
 *
 * 仕様書の「すべてデータ駆動（外部ファイル）にし、数値だけ差し替えられる」方針に従い、
 * バランスに関わる数字・敵・武器・カードなどを “ここだけ” に集めています。
 * ゲームの手応えを変えたいときは、原則このファイルの数値をいじるだけでOK。
 *
 * ※ ビルドなしで動かすため ES Modules（import/export）は使わず、
 *   普通の <script> として読み込み、グローバル変数として共有します。
 *   そのため index.html では data.js を一番最初に読み込みます。
 */

// ──────────────────────────────────────────
// プレイヤー初期値（主人公・仮名「ぽち」）
// ──────────────────────────────────────────
const PLAYER_INIT = {
  name: "ぽち",
  maxHp: 26,          // HP が 0 になると RUN OVER（最初から）
                      // ※20→26：序盤は群れの被弾が一気にかさむため、立て直す余裕を確保
  maxKokoro: 10,      // こころ＝やさしさ/問いかけのリソース。きいてみる／手をのばす で消費
                      // ※8→10：1ウェーブで“きいて、むかえる”を複数こなすには燃料がいる
  // 開始の きついことば（罵声）を複数に：最初から“言い方を選べる”手応えを出す。
  //   バカ＝単体強／だまれ＝単体軽い連打／うるさい＝前列2体。internal id は据え置き（互換のため）。
  startWeapons: ["namida", "damare", "poyo"],
  startWeapon: "namida", // （後方互換のため一応残す。実際は startWeapons を使う）
  startWords: [],     // 開始時に持っている“やさしいことば”（最初はまだ少ない＝言えることが増えていく成長）
  items: { heal: 3 }, // もちもの（おまもり）の初期所持
                      // ※2→3：単体ことばだと序盤の処理に手間取るので回復を1つ増量
};

// ──────────────────────────────────────────
// バランス調整値（“迷い”を生むためのコスト設計）
//   - 祓う＝1ターンで即・強くなる
//   - 救う＝数ターン＆こころ消費。その間も群れに殴られる
// この非対称さが本作の核なので、ここの数値で手触りが大きく変わります。
// ──────────────────────────────────────────
const BALANCE = {
  actCost: 1,             // こころみる1回で消費するこころ
  saveCost: 2,            // すくう1回で消費するこころ（救うのは“重い”）

  // ── こころ＝「ことばを発する力（心のゆとり）」に一本化 ──
  //   やさしさ(きいてみる/手をのばす)だけでなく、きついことば(ぶつける)も これを消費する。
  //   ＝残酷さを吐くほど、やさしくする余裕(こころ)が減る（ユーザーの「悪いこと言うと心が痛む」案）。
  //   ねらい：ぶつけるが“無料の一択”でなくなり、毎ターン「重い一撃で仕留める？/軽い手で凌いで
  //           こころを残す？」の天秤が生まれる（武器ごとの cost は WEAPONS 側に持たせる）。
  //   ★要素を増やさない方針：プレイヤーが“見て管理する数字”は こころ ひとつに集約する。
  //     （HP反動や新ゲージは足さない＝分かりにくさを避ける）
  kokoroRegenPerTurn: 2,     // 毎プレイヤーターン、こころが自然に戻る量（息をつく＝ハードロック防止）
  kokoroRegenDefendBonus: 2, // 「こらえる」ターンは追加で戻る（立て直しの一手に意味を持たせる）
  healAmount: 10,         // どうぐ（回復）の回復量
  defendReduction: 0.7,   // まもる：このターンの被ダメを70%カット
  weaponMaxLv: 3,         // 武器がこの Lv に達すると進化条件を満たす
  expPerKill: 3,          // 祓って倒したときの EXP（多い＝早く強くなる）
  expPerSave: 1,          // すくったときの EXP（少ない。代わりに記憶のカケラ）
  saveHeal: 3,            // すくう成功で回復する HP。
                          // ※救済ルートは手数が多く被弾もかさむので“詰む”。
                          //   「祓い＝EXP/速さ」「救い＝HP/持続」という非対称な見返りにし、
                          //   慈悲を選ぶほど夜を生き延びられる設計にする（仕様の二択を成立させる核）。
  expToBonusLevel: 12,    // EXP がこの量たまると、ボーナスでもう1回3択が出る
  refillKokoroEachWave: true, // 毎ウェーブ開始時にこころを最大まで回復
                              // （各ウェーブを“誰を救うかのトリアージ”にするため）
  healOnWaveStartPct: 0.5,    // ウェーブ開始時に最大HPの何割を回復するか（2ウェーブ目以降）
                              // ※HPはウェーブ間で自然回復しないと、1人で全6波を耐える総HPが
                              //   足りず数学的に詰む。各波を“立て直して挑む一戦”にするための一息。
                              //   0 にすれば「回復なし=高難度」、1.0 で毎波全快。
  eliteHpBonus: 1,        // 強化個体（ウェーブ5）の HP 上乗せ（→1：全体武器が雑魚を一撃で流せる線を残す）
  eliteAtkBonus: 0,       // 強化個体の 攻撃力 上乗せ（1→0：6体全員が+1だと1人では被弾が過大）
                          //   ※「強化＝硬い個体」の意味は HP 上乗せで表現。火力増は solo には酷なので外す
  hayaashiDodgeRate: 0.25,// パッシブ「はやあし」取得時、各被弾を無効化する確率
  fukaiBonus: 2,          // パッシブ「ふかいかなしみ」：悲しむ敵への与ダメ上乗せ
  okoriBonus: 1,          // パッシブ「おこりんぼ」：前列攻撃の与ダメ上乗せ

  // ── きずな（救った友の“恩返し”）＝救うメリットを手触りにする核 ──
  // 記憶のカケラ（＝これまで救った数）が、夜のあいだ群れの反撃をやわらげる。
  // 「祓い＝敵を消して被弾を減らす」のに対し、「救い＝友が増えて被弾を減らす」。
  //   どちらの道も“生き延びやすくなる”形をそろえることで、救う選択に明確な見返りを与える。
  //   救うほど効きが積み上がる＝ダダサバ的な「雪だるま」の気持ちよさを救済ルートにも。
  bondReducePerSave: 1,   // 救った友1人につき、群れの反撃の合計ダメージを 1 減らす
  bondReduceMax: 5,       // 軽減の上限（祓いを完全な下位互換にしないためのキャップ）

  // ── 街の友のきずな（v0.4 メタループ）＝「救った夜ほど次が楽」を控えめに持ち越す ──
  //   街に住む友（前の夜に救った子）も、夜のあいだ そっと かばってくれる。
  //   ただし合計は bondReduceMax(5) でクランプ＝積み過ぎても上限を超えない（祓いを腐らせない）。
  //   ※ balance-probe / headless-check は meta を初期化しないので、この項は無効化され従来と一致する。
  metaBondPerFriend: 1,   // 街の友1人につき 反撃を 1 軽減（在籍ぶん）
  metaBondMax: 2,         // 街の友ぶんの軽減の上限（持ち越しが強すぎないように小さく）

  // ※（旧 calmKokoroRegen「被弾0のターンだけ回復」は v0.7 で kokoroRegenPerTurn に統合・廃止。
  //   こころは毎ターン少しずつ戻るので、救いルートのソフトロックも自然に解消される。）

  // ── 口喧嘩バトル：2つの“雪だるまゲージ”（ことばの積み方＝ビルド）──
  // この夜の戦いは武器ではなく「ことば」で行う。
  //   ・きついことば（ぶつける）＝とげとげ → 速く強いが、世界がすこし翳る（狂気）
  //   ・やさしいことば（きいてみる/手をのばす）＝あたたかい → 遅いが誰も死なせない（ぬくもり）
  // ダダサバ的に「積むほど効く」スノーボールを救う側にも用意し、どちらの道も成立させる。
  kyokiDmgScale: 0.05,    // きついことばの与ダメ倍率＝(1 + 狂気 × これ)。0.05なら狂気10で+50%。
                          //   ※強くしすぎると“ぶつける一強”になるので控えめ。暫定値（要バランス検証）。
  kyokiPerHarsh: 1,       // きついことば1回で上がる狂気（ことば側で個別上書き可）
  kyokiMax: 12,           // 狂気の上限（与ダメ倍率の上限＝暴走しすぎ防止）
  nukumoriStep: 3,        // ぬくもりがこの数たまるごとに、下の恩恵が1回発火
  nukumoriHpBonus: 2,     // ぬくもり閾値ごとに 最大HP＋（やさしく言うほど夜に強くなる＝救いの見返り）
  nukumoriHealBonus: 2,   // ぬくもり閾値ごとに 即時HP回復（その場のあたたかさ）
};

// ──────────────────────────────────────────
